const dragonballQuestions = [
  {t:"m",q:"\u00bfCu\u00e1l es el nombre saiyajin de Goku?",o:["Kakarotto", "Bardock", "Raditz", "Vegeta"],a:0,exp:"El nombre saiyajin de Goku es Kakarotto.",extra:"Goku fue enviado a la Tierra siendo beb\u00e9, como parte de la costumbre saiyajin de mandar ni\u00f1os a planetas lejanos. Tras golpearse la cabeza, perdi\u00f3 su agresividad original y fue criado por Son Gohan."},
  {t:"m",q:"\u00bfQui\u00e9n encontr\u00f3 y cri\u00f3 a Goku cuando era beb\u00e9?",o:["Maestro Roshi", "Son Gohan", "Bulma", "Kami-sama"],a:1,exp:"Son Gohan, un anciano artista marcial, encontr\u00f3 a Goku y lo cri\u00f3 como nieto.",extra:"El nombre de Gohan, hijo de Goku, es un homenaje directo a este abuelo adoptivo. La influencia de Son Gohan fue clave para que Goku creciera con bondad y no como conquistador saiyajin."},
  {t:"m",q:"\u00bfQu\u00e9 objeto buscaba Bulma al inicio de Dragon Ball?",o:["Las Esferas del Drag\u00f3n", "La espada Z", "El radar scouter", "Las semillas del ermita\u00f1o"],a:0,exp:"Bulma buscaba las Esferas del Drag\u00f3n para invocar a Shenlong y pedir un deseo.",extra:"El encuentro entre Bulma y Goku inicia toda la aventura. En sus comienzos, Dragon Ball era m\u00e1s una historia de viaje, humor y fantas\u00eda que una saga de combates c\u00f3smicos."},
  {t:"m",q:"\u00bfCu\u00e1ntas Esferas del Drag\u00f3n hay en la Tierra?",o:["5", "6", "7", "9"],a:2,exp:"Las Esferas del Drag\u00f3n de la Tierra son siete.",extra:"Al reunirlas, se puede invocar a Shenlong. Despu\u00e9s de conceder un deseo, las esferas se dispersan por el mundo y se vuelven piedra durante un tiempo."},
  {t:"m",q:"\u00bfC\u00f3mo se llama el drag\u00f3n invocado por las Esferas del Drag\u00f3n de la Tierra?",o:["Porunga", "Shenlong", "Polunga", "Icarus"],a:1,exp:"El drag\u00f3n de la Tierra se llama Shenlong.",extra:"Shenlong fue creado por Kami-sama y luego mejorado por Dende. Sus l\u00edmites dependen directamente del poder de su creador."},
  {t:"m",q:"\u00bfQu\u00e9 arte marcial entrena Goku con el Maestro Roshi?",o:["Escuela Tortuga", "Escuela Grulla", "Estilo Saiyajin", "Estilo Namekiano"],a:0,exp:"Goku entrena bajo la Escuela Tortuga del Maestro Roshi.",extra:"La Escuela Tortuga ense\u00f1a no solo combate, sino disciplina, esfuerzo f\u00edsico y alegr\u00eda por vivir. Su s\u00edmbolo, el kanji kame, se vuelve ic\u00f3nico en el uniforme de Goku."},
  {t:"m",q:"\u00bfCu\u00e1l es la t\u00e9cnica m\u00e1s famosa del Maestro Roshi?",o:["Makankosappo", "Kamehameha", "Final Flash", "Galick Ho"],a:1,exp:"El Kamehameha es la t\u00e9cnica m\u00e1s famosa del Maestro Roshi y luego de Goku.",extra:"Aunque Roshi tard\u00f3 d\u00e9cadas en perfeccionarla, Goku la aprende casi instant\u00e1neamente al verla, mostrando desde temprano su talento monstruoso."},
  {t:"m",q:"\u00bfQui\u00e9n fue el primer gran rival de Goku en los torneos de artes marciales?",o:["Yamcha", "Krillin", "Tenshinhan", "Piccolo Jr."],a:2,exp:"Tenshinhan fue uno de los primeros rivales realmente serios de Goku en el Tenkaichi Budokai.",extra:"Tenshinhan empez\u00f3 como alumno de la Escuela Grulla y rival hostil, pero termin\u00f3 convirti\u00e9ndose en aliado y guerrero honorable."},
  {t:"m",q:"\u00bfQui\u00e9n es el mejor amigo humano de Goku desde su entrenamiento con Roshi?",o:["Yamcha", "Krillin", "Oolong", "Tenshinhan"],a:1,exp:"Krillin se convierte en el mejor amigo de Goku tras entrenar juntos con el Maestro Roshi.",extra:"Su amistad atraviesa toda la serie. La muerte de Krillin a manos de Freezer es el detonante emocional que despierta por primera vez al Super Saiyajin en Goku."},
  {t:"m",q:"\u00bfQu\u00e9 transformaci\u00f3n sufre Goku cuando mira la luna llena de ni\u00f1o?",o:["Super Saiyajin", "Ozaru", "Kaioken", "Ultra Instinto"],a:1,exp:"Goku se transforma en Ozaru, un mono gigante, al mirar la luna llena.",extra:"Esta transformaci\u00f3n es propia de los saiyajin con cola. Durante mucho tiempo, Goku no sabe que \u00e9l mismo caus\u00f3 accidentalmente la muerte de su abuelo adoptivo en esa forma."},
  {t:"m",q:"\u00bfQu\u00e9 parte del cuerpo saiyajin permite la transformaci\u00f3n en Ozaru?",o:["La cola", "Los ojos", "El cabello", "El coraz\u00f3n"],a:0,exp:"La cola saiyajin permite transformarse en Ozaru al recibir ondas Blutz de la luna llena.",extra:"Cortar la cola cancela la transformaci\u00f3n. En la saga saiyajin, Vegeta usa una luna artificial para convertirse en Ozaru durante su pelea contra Goku."},
  {t:"m",q:"\u00bfQui\u00e9n es el hermano biol\u00f3gico de Goku?",o:["Vegeta", "Raditz", "Nappa", "Turles"],a:1,exp:"Raditz es el hermano mayor de Goku.",extra:"Su llegada al inicio de Dragon Ball Z revela que Goku no es humano, sino un saiyajin enviado originalmente para conquistar la Tierra."},
  {t:"m",q:"\u00bfQui\u00e9n mata a Raditz?",o:["Goku solo", "Piccolo con ayuda de Goku", "Vegeta", "Gohan"],a:1,exp:"Piccolo mata a Raditz con el Makankosappo mientras Goku lo sujeta.",extra:"La escena tambi\u00e9n causa la muerte de Goku. Es una de las primeras se\u00f1ales de que Dragon Ball Z tendr\u00eda consecuencias m\u00e1s dram\u00e1ticas que la etapa original."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica perforadora usa Piccolo contra Raditz?",o:["Kamehameha", "Makankosappo", "Masenko", "Dodonpa"],a:1,exp:"Piccolo usa el Makankosappo, tambi\u00e9n conocido como Special Beam Cannon.",extra:"La t\u00e9cnica tarda en cargarse, pero concentra un poder penetrante enorme. Piccolo la desarroll\u00f3 originalmente para matar a Goku."},
  {t:"m",q:"\u00bfQui\u00e9n entrena a Gohan durante la llegada de los saiyajin?",o:["Goku", "Piccolo", "Maestro Roshi", "Vegeta"],a:1,exp:"Piccolo entrena a Gohan para prepararlo contra Vegeta y Nappa.",extra:"La relaci\u00f3n entre Piccolo y Gohan transforma profundamente a Piccolo. Pasa de enemigo de Goku a figura protectora y casi paterna para Gohan."},
  {t:"m",q:"\u00bfQui\u00e9nes llegan a la Tierra tras la muerte de Raditz?",o:["Freezer y Zarbon", "Vegeta y Nappa", "Cell y los androides", "Bills y Whis"],a:1,exp:"Vegeta y Nappa llegan a la Tierra buscando las Esferas del Drag\u00f3n.",extra:"Su llegada eleva la escala de la serie: los enemigos ya no son luchadores terrestres, sino guerreros espaciales de una raza conquistadora."},
  {t:"m",q:"\u00bfQu\u00e9 guerrero humano muere usando una t\u00e9cnica suicida contra Nappa?",o:["Krillin", "Yamcha", "Chaoz", "Yajirobe"],a:2,exp:"Chaoz se sacrifica intentando destruir a Nappa, aunque no logra matarlo.",extra:"La muerte de Chaoz es uno de los momentos m\u00e1s duros de la saga saiyajin y muestra la diferencia brutal de poder entre los terrestres y los invasores."},
  {t:"m",q:"\u00bfQui\u00e9n corta la cola de Vegeta en forma Ozaru?",o:["Krillin", "Yajirobe", "Gohan", "Piccolo"],a:1,exp:"Yajirobe corta la cola de Vegeta, oblig\u00e1ndolo a volver a su forma normal.",extra:"Aunque suele ser c\u00f3mico y cobarde, Yajirobe cumple un papel decisivo en la batalla contra Vegeta."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica multiplica temporalmente el poder de Goku tras entrenar con Kaio-sama?",o:["Kaioken", "Genkidama", "Ultra Instinto", "Fusi\u00f3n"],a:0,exp:"El Kaioken permite a Goku multiplicar su poder durante un tiempo limitado.",extra:"Es una t\u00e9cnica arriesgada porque da\u00f1a el cuerpo si se usa por encima de sus l\u00edmites. Goku la combina con el Kamehameha contra Vegeta."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica re\u00fane energ\u00eda de seres vivos?",o:["Genkidama", "Final Flash", "Masenko", "Big Bang Attack"],a:0,exp:"La Genkidama re\u00fane energ\u00eda de seres vivos, planetas y naturaleza.",extra:"Es una t\u00e9cnica de Kaio-sama. Goku la usa contra Vegeta, Freezer, Kid Buu y otros enemigos, aunque requiere tiempo y concentraci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 planeta visitan los h\u00e9roes para conseguir nuevas Esferas del Drag\u00f3n tras la saga saiyajin?",o:["Namek", "Yardrat", "Vegeta", "Kanassa"],a:0,exp:"Los h\u00e9roes viajan a Namek para buscar las Esferas del Drag\u00f3n namekianas.",extra:"El viaje a Namek permite resucitar a los ca\u00eddos y abre la saga de Freezer, una de las m\u00e1s importantes de Dragon Ball Z."},
  {t:"m",q:"\u00bfC\u00f3mo se llama el drag\u00f3n de las Esferas del Drag\u00f3n de Namek?",o:["Shenlong", "Porunga", "Shinron", "Zalama"],a:1,exp:"El drag\u00f3n de Namek se llama Porunga.",extra:"Porunga puede conceder tres deseos, aunque originalmente solo pod\u00eda resucitar a una persona por deseo. Sus reglas son distintas a las de Shenlong."},
  {t:"m",q:"\u00bfQui\u00e9n es el gran villano de la saga de Namek?",o:["Cell", "Freezer", "Majin Buu", "Garlic Jr."],a:1,exp:"Freezer es el villano principal de la saga de Namek.",extra:"Freezer es responsable de la destrucci\u00f3n del planeta Vegeta y del casi exterminio de los saiyajin, convirti\u00e9ndolo en enemigo hist\u00f3rico de Goku y Vegeta."},
  {t:"m",q:"\u00bfQu\u00e9 raza extermin\u00f3 Freezer casi por completo?",o:["Namekianos", "Saiyajin", "Terr\u00edcolas", "Kaioshin"],a:1,exp:"Freezer destruy\u00f3 el planeta Vegeta y casi extermin\u00f3 a los saiyajin.",extra:"Lo hizo por miedo al mito del Super Saiyajin y al potencial rebelde de la raza saiyajin."},
  {t:"m",q:"\u00bfQu\u00e9 desencadena la primera transformaci\u00f3n de Goku en Super Saiyajin?",o:["La muerte de Vegeta", "La muerte de Krillin", "La destrucci\u00f3n de Namek", "La derrota de Gohan"],a:1,exp:"Goku se transforma en Super Saiyajin tras ver a Freezer matar a Krillin.",extra:"Es uno de los momentos m\u00e1s ic\u00f3nicos del anime. La leyenda del Super Saiyajin, mencionada durante la saga, se vuelve realidad por la furia y el dolor de Goku."},
  {t:"m",q:"\u00bfQu\u00e9 color caracteriza el cabello del Super Saiyajin cl\u00e1sico?",o:["Negro", "Azul", "Dorado", "Rojo"],a:2,exp:"El Super Saiyajin cl\u00e1sico se caracteriza por cabello dorado y aura intensa.",extra:"La transformaci\u00f3n cambi\u00f3 la cultura popular del anime. Desde entonces, Dragon Ball se asoci\u00f3 fuertemente con escaladas de poder y transformaciones."},
  {t:"m",q:"\u00bfQui\u00e9n derrota finalmente a Freezer en Namek?",o:["Gohan", "Vegeta", "Goku", "Trunks"],a:2,exp:"Goku derrota a Freezer en Namek como Super Saiyajin.",extra:"Aunque Freezer sobrevive inicialmente, queda humillado. M\u00e1s tarde regresa como Mecha Freezer y es derrotado por Trunks del futuro."},
  {t:"m",q:"\u00bfQui\u00e9n llega del futuro y derrota a Mecha Freezer?",o:["Gohan del futuro", "Trunks", "Goten", "Cell"],a:1,exp:"Trunks del futuro llega a la Tierra y derrota f\u00e1cilmente a Mecha Freezer.",extra:"Su aparici\u00f3n es impactante porque tambi\u00e9n se transforma en Super Saiyajin, revelando que la transformaci\u00f3n ya no es exclusiva de Goku."},
  {t:"m",q:"\u00bfDe qui\u00e9n es hijo Trunks del futuro?",o:["Goku y Milk", "Vegeta y Bulma", "Gohan y Videl", "Krillin y 18"],a:1,exp:"Trunks es hijo de Vegeta y Bulma.",extra:"La revelaci\u00f3n sorprendi\u00f3 porque Vegeta y Bulma no parec\u00edan una pareja probable al inicio, pero su relaci\u00f3n se volvi\u00f3 una de las m\u00e1s importantes de la saga."},
  {t:"m",q:"\u00bfQu\u00e9 enfermedad mata a Goku en la l\u00ednea temporal de Trunks?",o:["Virus del coraz\u00f3n", "C\u00e1ncer de ki", "Veneno namekiano", "Maldici\u00f3n saiyajin"],a:0,exp:"En la l\u00ednea temporal de Trunks, Goku muere por un virus del coraz\u00f3n.",extra:"Trunks viaja al pasado para darle una medicina a Goku y advertir sobre la llegada de los androides."},
  {t:"m",q:"\u00bfQui\u00e9n cre\u00f3 a los androides 17 y 18?",o:["Dr. Gero", "Dr. Brief", "Dr. Myuu", "Dr. Wheelo"],a:0,exp:"El Dr. Gero, cient\u00edfico del Ej\u00e9rcito Red Ribbon, cre\u00f3 a los androides.",extra:"Gero busca vengarse de Goku por destruir el Red Ribbon en la infancia, conectando Dragon Ball cl\u00e1sico con la saga de Cell."},
  {t:"m",q:"\u00bfQu\u00e9 androide se casa m\u00e1s adelante con Krillin?",o:["Androide 16", "Androide 17", "Androide 18", "Androide 19"],a:2,exp:"Androide 18 se casa con Krillin.",extra:"Su relaci\u00f3n es una de las m\u00e1s inesperadas y queridas. Tienen una hija llamada Marron."},
  {t:"m",q:"\u00bfQu\u00e9 bioandroide necesita absorber a 17 y 18 para alcanzar su forma perfecta?",o:["Cell", "Majin Buu", "Android 13", "Baby"],a:0,exp:"Cell necesita absorber a los androides 17 y 18 para alcanzar su forma perfecta.",extra:"Cell fue creado con c\u00e9lulas de muchos guerreros, incluyendo Goku, Vegeta, Piccolo, Freezer y King Cold."},
  {t:"m",q:"\u00bfQui\u00e9n alcanza el Super Saiyajin 2 por primera vez contra Cell?",o:["Goku", "Vegeta", "Gohan", "Trunks"],a:2,exp:"Gohan alcanza el Super Saiyajin 2 durante los Cell Games.",extra:"La transformaci\u00f3n ocurre tras la muerte del Androide 16 y la presi\u00f3n emocional acumulada sobre Gohan."},
  {t:"m",q:"\u00bfQui\u00e9n derrota finalmente a Cell?",o:["Goku", "Gohan", "Vegeta", "Piccolo"],a:1,exp:"Gohan derrota a Cell con un Kamehameha padre-hijo.",extra:"Aunque Goku est\u00e1 muerto en ese momento, anima espiritualmente a Gohan. Vegeta tambi\u00e9n ayuda distrayendo a Cell en el instante decisivo."},
  {t:"m",q:"\u00bfPor qu\u00e9 Goku decide permanecer muerto tras la saga de Cell?",o:["Porque pierde sus poderes", "Porque cree atraer amenazas a la Tierra", "Porque no puede resucitar", "Porque se convierte en Kaioshin"],a:1,exp:"Goku piensa que muchas amenazas llegan a la Tierra por su causa y decide quedarse en el Otro Mundo.",extra:"Esa decisi\u00f3n deja a Gohan como posible protector principal de la Tierra, aunque la saga de Buu toma otro camino."},
  {t:"m",q:"\u00bfQu\u00e9 identidad superheroica usa Gohan en la saga de Buu?",o:["Saiyaman", "Great Saiyaman", "Golden Fighter", "Masked Warrior"],a:1,exp:"Gohan adopta la identidad de Great Saiyaman.",extra:"La etapa de Great Saiyaman mezcla comedia, vida escolar y superhero\u00edsmo. Tambi\u00e9n introduce su relaci\u00f3n con Videl."},
  {t:"m",q:"\u00bfQui\u00e9n es la hija de Mr. Satan y pareja de Gohan?",o:["Bulma", "Videl", "Marron", "Pan"],a:1,exp:"Videl es hija de Mr. Satan y m\u00e1s tarde pareja de Gohan.",extra:"Videl aprende a controlar el ki y descubre r\u00e1pidamente que Gohan oculta algo. Su hija con Gohan se llama Pan."},
  {t:"m",q:"\u00bfQu\u00e9 mago libera a Majin Buu?",o:["Babid\u00ed", "Babidi", "Dabura", "Bibidi"],a:1,exp:"Babidi es el mago que busca liberar a Majin Buu.",extra:"Bibidi fue el creador original de Buu, mientras Babidi intenta revivirlo manipulando guerreros y recolectando energ\u00eda."},
  {t:"m",q:"\u00bfQu\u00e9 rey demonio sirve a Babidi?",o:["Dabura", "Janemba", "Garlic Jr.", "Moro"],a:0,exp:"Dabura, rey del mundo demon\u00edaco, sirve a Babidi.",extra:"Dabura convierte personas en piedra con su saliva y es lo suficientemente fuerte como para preocupar a los h\u00e9roes al inicio de la saga."},
  {t:"m",q:"\u00bfQu\u00e9 transformaci\u00f3n alcanza Goku por primera vez en la saga de Buu?",o:["Super Saiyajin 3", "Super Saiyajin Dios", "Ultra Instinto", "Super Saiyajin Blue"],a:0,exp:"Goku revela el Super Saiyajin 3 durante su combate contra Majin Buu.",extra:"La transformaci\u00f3n tiene cabello extremadamente largo y sin cejas, pero consume much\u00edsima energ\u00eda, especialmente en el mundo de los vivos."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica permite fusionar a Goten y Trunks?",o:["Pendientes Pothala", "Danza de la Fusi\u00f3n", "Kaioken doble", "Absorci\u00f3n Majin"],a:1,exp:"Goten y Trunks se fusionan mediante la Danza de la Fusi\u00f3n para formar a Gotenks.",extra:"La t\u00e9cnica requiere que ambos usuarios tengan poder similar y realicen movimientos exactos. Si fallan, la fusi\u00f3n sale defectuosa."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la fusi\u00f3n de Goten y Trunks?",o:["Vegito", "Gogeta", "Gotenks", "Trunkten"],a:2,exp:"La fusi\u00f3n de Goten y Trunks se llama Gotenks.",extra:"Gotenks es poderoso pero muy inmaduro. Sus t\u00e9cnicas tienen nombres rid\u00edculos y teatrales, reflejando la personalidad de ambos ni\u00f1os."},
  {t:"m",q:"\u00bfQu\u00e9 objeto fusiona a Goku y Vegeta en Vegito?",o:["Pendientes Pothala", "Danza de la Fusi\u00f3n", "Esferas del Drag\u00f3n", "Espada Z"],a:0,exp:"Los pendientes Pothala fusionan a Goku y Vegeta en Vegito.",extra:"En Dragon Ball Z se presenta como una fusi\u00f3n permanente para mortales, aunque Dragon Ball Super modifica esta regla con l\u00edmite temporal seg\u00fan el caso."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la fusi\u00f3n de Goku y Vegeta mediante danza?",o:["Vegito", "Gogeta", "Gotenks", "Vegeku"],a:1,exp:"La fusi\u00f3n mediante la Danza de la Fusi\u00f3n se llama Gogeta.",extra:"Gogeta aparece de forma destacada en pel\u00edculas y luego en Dragon Ball Super: Broly, donde se vuelve parte de la continuidad moderna."},
  {t:"m",q:"\u00bfQui\u00e9n derrota finalmente a Kid Buu?",o:["Gohan", "Vegeta", "Goku con una Genkidama", "Gotenks"],a:2,exp:"Goku derrota a Kid Buu usando una Genkidama formada con energ\u00eda de la Tierra.",extra:"Mr. Satan cumple un papel clave convenciendo a la humanidad de prestar energ\u00eda, demostrando que su influencia social puede salvar el planeta."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la reencarnaci\u00f3n humana de Kid Buu?",o:["Uub", "Pan", "Majuub", "Buu Jr."],a:0,exp:"Uub es la reencarnaci\u00f3n humana de Kid Buu.",extra:"Goku lo encuentra al final de Dragon Ball Z y decide entrenarlo, cerrando la historia con una nueva generaci\u00f3n de potencial enorme."},
  {t:"m",q:"\u00bfQui\u00e9n es el Dios de la Destrucci\u00f3n del Universo 7?",o:["Whis", "Bills", "Zeno", "Champa"],a:1,exp:"Bills, tambi\u00e9n conocido como Beerus, es el Dios de la Destrucci\u00f3n del Universo 7.",extra:"Su llegada en Battle of Gods abre Dragon Ball hacia una escala multiversal con dioses, \u00e1ngeles y universos paralelos."},
  {t:"m",q:"\u00bfQui\u00e9n es el asistente y maestro de Bills?",o:["Whis", "Vados", "Daishinkan", "Kaioshin"],a:0,exp:"Whis es el \u00e1ngel asistente y maestro de Bills.",extra:"Whis es mucho m\u00e1s poderoso que Bills, aunque su rol no es intervenir libremente en los asuntos del universo."},
  {t:"m",q:"\u00bfQu\u00e9 transformaci\u00f3n alcanza Goku mediante el ritual de saiyajins en Battle of Gods?",o:["Super Saiyajin 3", "Super Saiyajin Dios", "Super Saiyajin 4", "Ultra Instinto"],a:1,exp:"Goku alcanza el Super Saiyajin Dios mediante un ritual con energ\u00eda de saiyajins de coraz\u00f3n puro.",extra:"Esta forma introduce el ki divino, una categor\u00eda de poder distinta al ki normal percibido por mortales."},
  {t:"m",q:"\u00bfQu\u00e9 transformaci\u00f3n combina el poder de Super Saiyajin con ki divino?",o:["Super Saiyajin Blue", "Super Saiyajin 2", "Ozaru Dorado", "Kaioken"],a:0,exp:"Super Saiyajin Blue combina la forma Super Saiyajin con el ki del Super Saiyajin Dios.",extra:"Goku y Vegeta usan esta forma durante buena parte de Dragon Ball Super, especialmente contra Freezer dorado, Hit, Zamasu y en el Torneo de Poder."},
  {t:"m",q:"\u00bfQu\u00e9 forma obtiene Freezer tras entrenar por primera vez seriamente?",o:["Golden Freezer", "Metal Freezer", "Black Freezer", "Final Freezer"],a:0,exp:"Freezer obtiene la forma Golden Freezer tras entrenar durante unos meses.",extra:"Freezer era tan talentoso que nunca hab\u00eda necesitado entrenar antes. Su nueva forma muestra el potencial absurdo de su raza."},
  {t:"m",q:"\u00bfQu\u00e9 asesino del Universo 6 puede saltar brevemente en el tiempo?",o:["Hit", "Jiren", "Toppo", "Cabba"],a:0,exp:"Hit usa una t\u00e9cnica de salto temporal llamada Time-Skip.",extra:"Su combate contra Goku en el torneo entre Universos 6 y 7 es uno de los primeros grandes desaf\u00edos de Dragon Ball Super."},
  {t:"m",q:"\u00bfQui\u00e9n es el saiyajin del Universo 6 que conoce a Vegeta?",o:["Cabba", "Caulifla", "Kale", "Tarble"],a:0,exp:"Cabba es un saiyajin del Universo 6 y desarrolla una relaci\u00f3n de respeto con Vegeta.",extra:"Vegeta act\u00faa casi como mentor duro para Cabba, ense\u00f1\u00e1ndole el Super Saiyajin y conectando con una versi\u00f3n distinta de la raza saiyajin."},
  {t:"m",q:"\u00bfQu\u00e9 saiyajin del Universo 6 tiene una forma similar al Super Saiyajin legendario?",o:["Caulifla", "Kale", "Vados", "Ribrianne"],a:1,exp:"Kale posee una transformaci\u00f3n berserker parecida al Super Saiyajin legendario.",extra:"Su v\u00ednculo con Caulifla es central para controlar su poder y formar m\u00e1s tarde la fusi\u00f3n Kefla."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la fusi\u00f3n Pothala de Caulifla y Kale?",o:["Kefla", "Kafla", "Caulale", "Kaleifla"],a:0,exp:"Caulifla y Kale se fusionan en Kefla usando pendientes Pothala.",extra:"Kefla es una de las rivales m\u00e1s explosivas del Torneo de Poder y obliga a Goku a usar el Ultra Instinto Se\u00f1al."},
  {t:"m",q:"\u00bfQu\u00e9 guerrero del Universo 11 es el rival m\u00e1s fuerte de Goku en el Torneo de Poder?",o:["Toppo", "Dyspo", "Jiren", "Hit"],a:2,exp:"Jiren es el guerrero m\u00e1s poderoso del Universo 11 durante el Torneo de Poder.",extra:"Su poder supera incluso a muchos dioses de la destrucci\u00f3n en ciertos aspectos, convirti\u00e9ndolo en el muro definitivo para Goku."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica divina despierta Goku durante el Torneo de Poder?",o:["Ultra Instinto", "Kaioken Supremo", "Super Saiyajin 5", "Instinto Saiyajin"],a:0,exp:"Goku despierta el Ultra Instinto durante el Torneo de Poder.",extra:"El Ultra Instinto permite que el cuerpo reaccione sin que la mente interfiera, una t\u00e9cnica incluso dif\u00edcil para los dioses."},
  {t:"m",q:"\u00bfQui\u00e9n gana oficialmente el Torneo de Poder?",o:["Goku", "Jiren", "Androide 17", "Freezer"],a:2,exp:"Androide 17 es el \u00faltimo combatiente en pie y gana el Torneo de Poder.",extra:"Su deseo con las Super Dragon Balls restaura los universos borrados, mostrando que su aparente frialdad ocultaba una gran nobleza."},
  {t:"m",q:"\u00bfQu\u00e9 drag\u00f3n se invoca con las Super Dragon Balls?",o:["Shenlong", "Porunga", "Super Shenlong", "Omega Shenron"],a:2,exp:"Las Super Dragon Balls invocan a Super Shenlong.",extra:"Son esferas del tama\u00f1o de planetas y tienen un poder de deseo pr\u00e1cticamente ilimitado, muy superior al de las esferas terrestres o namekianas."},
  {t:"m",q:"\u00bfQui\u00e9n es el rey de todos los universos?",o:["Daishinkan", "Zeno-sama", "Bills", "Kaioshin"],a:1,exp:"Zeno-sama es el rey de todos los universos.",extra:"Aunque tiene apariencia infantil, su poder es absoluto: puede borrar universos enteros sin esfuerzo."},
  {t:"m",q:"\u00bfQui\u00e9n es el padre de Goku?",o:["Bardock", "Paragus", "King Vegeta", "Raditz"],a:0,exp:"Bardock es el padre biol\u00f3gico de Goku.",extra:"Bardock era un guerrero saiyajin de clase baja. Las versiones de su historia var\u00edan, pero siempre est\u00e1 ligado a la destrucci\u00f3n del planeta Vegeta."},
  {t:"m",q:"\u00bfQui\u00e9n es la madre de Goku?",o:["Gine", "Fasha", "Bulma", "Caulifla"],a:0,exp:"La madre de Goku se llama Gine.",extra:"Gine aparece en material moderno como Dragon Ball Minus y Dragon Ball Super: Broly, mostrando un lado m\u00e1s familiar y afectivo de los saiyajin."},
  {t:"m",q:"\u00bfQui\u00e9n es el padre de Vegeta?",o:["King Vegeta", "Bardock", "Paragus", "Nappa"],a:0,exp:"El padre de Vegeta fue el Rey Vegeta.",extra:"Vegeta carga con el orgullo de ser pr\u00edncipe de una raza destruida, algo que explica gran parte de su arrogancia y trauma inicial."},
  {t:"m",q:"\u00bfQu\u00e9 saiyajin legendario fue reintroducido en la continuidad moderna con una pel\u00edcula de Dragon Ball Super?",o:["Turles", "Broly", "Raditz", "Nappa"],a:1,exp:"Broly fue reintroducido oficialmente en Dragon Ball Super: Broly.",extra:"La versi\u00f3n moderna de Broly es m\u00e1s tr\u00e1gica y menos villanesca que la de las pel\u00edculas cl\u00e1sicas, con una historia marcada por exilio y abuso de Paragus."},
  {t:"m",q:"\u00bfQui\u00e9n es el padre de Broly?",o:["Paragus", "Bardock", "King Vegeta", "Nappa"],a:0,exp:"Paragus es el padre de Broly.",extra:"Paragus cr\u00eda a Broly en el planeta Vampa y usa un dispositivo para controlar su poder, lo que da\u00f1a profundamente su relaci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 raza son Piccolo y Kami-sama?",o:["Saiyajin", "Namekianos", "Shinjin", "Terr\u00edcolas"],a:1,exp:"Piccolo y Kami-sama son namekianos.",extra:"Originalmente fueron dos mitades separadas de un mismo ser namekiano: una parte maligna y una parte divina."},
  {t:"m",q:"\u00bfQu\u00e9 ocurre cuando Piccolo se fusiona con Kami-sama?",o:["Muere", "Recupera una forma namekiana m\u00e1s completa y poderosa", "Se vuelve humano", "Pierde sus poderes"],a:1,exp:"Piccolo se vuelve mucho m\u00e1s poderoso al reunificarse con Kami-sama.",extra:"Esta fusi\u00f3n le permite enfrentarse de igual a igual con Androide 17 por un tiempo, convirti\u00e9ndolo otra vez en uno de los guerreros principales."},
  {t:"m",q:"\u00bfQui\u00e9n reemplaza a Kami-sama como guardi\u00e1n de la Tierra?",o:["Dende", "Piccolo", "Kaio-sama", "Mr. Popo"],a:0,exp:"Dende se convierte en el nuevo guardi\u00e1n de la Tierra.",extra:"Gracias a Dende, las Esferas del Drag\u00f3n de la Tierra son restauradas y mejoradas tras la fusi\u00f3n de Piccolo y Kami-sama."},
  {t:"m",q:"\u00bfQui\u00e9n es el asistente de Kami-sama en el templo?",o:["Mr. Popo", "Korin", "Yajirobe", "Kaio-sama"],a:0,exp:"Mr. Popo es el asistente de Kami-sama en el templo sagrado.",extra:"Mr. Popo ayuda en entrenamientos y mantenimiento del templo. Aunque suele estar en segundo plano, es una figura antigua y misteriosa."},
  {t:"m",q:"\u00bfQu\u00e9 gato sabio vive en la Torre de Karin?",o:["Korin", "Puar", "Beerus", "Oolong"],a:0,exp:"Korin es el gato sabio que vive en la Torre de Karin.",extra:"Korin entrena a Goku en su juventud y le entrega semillas del ermita\u00f1o, objetos vitales para recuperar energ\u00eda y sanar heridas."},
  {t:"m",q:"\u00bfQu\u00e9 objeto cura heridas y restaura energ\u00eda casi por completo?",o:["Semilla del ermita\u00f1o", "Radar del drag\u00f3n", "Nube Kinton", "Agua sagrada"],a:0,exp:"Las semillas del ermita\u00f1o restauran energ\u00eda y curan heridas graves.",extra:"Son extremadamente valiosas en combate. Muchas batallas cambian de rumbo gracias a una sola semilla bien usada."},
  {t:"m",q:"\u00bfQu\u00e9 nube m\u00e1gica puede montar Goku de ni\u00f1o?",o:["Kinton", "Nimbus Oscura", "Nube Kai", "Kame Cloud"],a:0,exp:"Goku monta la Nube Kinton, que solo acepta personas de coraz\u00f3n puro.",extra:"La Kinton es uno de los s\u00edmbolos m\u00e1s queridos de la etapa cl\u00e1sica, antes de que el vuelo mediante ki se volviera com\u00fan."},
  {t:"m",q:"\u00bfQui\u00e9n cre\u00f3 el radar del drag\u00f3n?",o:["Bulma", "Dr. Brief", "Dr. Gero", "Pilaf"],a:0,exp:"Bulma cre\u00f3 el radar del drag\u00f3n para localizar las Esferas del Drag\u00f3n.",extra:"El radar demuestra desde el inicio que Bulma es una genio tecnol\u00f3gica, incluso antes de que Capsule Corp se vuelva central en la historia."},
  {t:"m",q:"\u00bfQu\u00e9 empresa pertenece a la familia de Bulma?",o:["Capsule Corp", "Red Ribbon", "West City Labs", "Brief Industries"],a:0,exp:"La familia Brief dirige Capsule Corp.",extra:"Capsule Corp cre\u00f3 las c\u00e1psulas hoi-poi, capaces de guardar veh\u00edculos, casas y objetos enormes en peque\u00f1os contenedores."},
  {t:"m",q:"\u00bfQui\u00e9n es el primer esposo de Bulma?",o:["Yamcha", "Vegeta", "Goku", "Trunks"],a:1,exp:"Bulma termina formando pareja con Vegeta.",extra:"Antes tuvo una relaci\u00f3n larga e inestable con Yamcha, pero finalmente construye una familia con Vegeta y tienen a Trunks y Bra."},
  {t:"m",q:"\u00bfQui\u00e9n es Mr. Satan?",o:["Un campe\u00f3n mundial de artes marciales humano", "Un saiyajin oculto", "Un androide", "Un Kaioshin"],a:0,exp:"Mr. Satan es un campe\u00f3n humano de artes marciales famoso mundialmente.",extra:"Aunque es d\u00e9bil frente a los guerreros Z, cumple roles decisivos contra Cell y Buu gracias a su fama, carisma y humanidad."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la hija de Gohan y Videl?",o:["Marron", "Pan", "Bra", "Bulla"],a:1,exp:"La hija de Gohan y Videl se llama Pan.",extra:"Pan tiene sangre saiyajin y humana. Aparece al final de Dragon Ball Z y tiene un rol mayor en Dragon Ball GT."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la hija de Krillin y Androide 18?",o:["Marron", "Pan", "Bra", "Launch"],a:0,exp:"La hija de Krillin y Androide 18 se llama Marron.",extra:"Su nombre recuerda a Maron, una antigua novia de Krillin en el anime, aunque son personajes distintos."},
  {t:"m",q:"\u00bfQui\u00e9n es el Supremo Kai del Universo 7 durante la saga de Buu?",o:["Shin", "Zamasu", "Gowasu", "Kibito"],a:0,exp:"Shin es el Supremo Kai que aparece durante la saga de Majin Buu.",extra:"Aunque su rango es alt\u00edsimo, se sorprende muchas veces por el poder de los saiyajin, especialmente Goku, Vegeta y Gohan."},
  {t:"m",q:"\u00bfQu\u00e9 espada sagrada libera accidentalmente al Anciano Kaioshin?",o:["Espada Z", "Espada de Trunks", "Yajirobe Blade", "Espada de Tapion"],a:0,exp:"La Espada Z contiene sellado al Anciano Kaioshin.",extra:"Cuando la espada se rompe, el Anciano Kaioshin queda libre y desbloquea el potencial oculto de Gohan."},
  {t:"m",q:"\u00bfQu\u00e9 forma obtiene Gohan tras el ritual del Anciano Kaioshin?",o:["Gohan Definitivo", "Super Saiyajin 3", "Super Saiyajin Dios", "Ozaru Humano"],a:0,exp:"Gohan obtiene su estado definitivo, tambi\u00e9n llamado Mystic o Ultimate Gohan.",extra:"Esta forma libera su potencial sin necesidad de transformarse en Super Saiyajin, representando un camino propio para Gohan."},
  {t:"m",q:"\u00bfQu\u00e9 ataque caracter\u00edstico usa Vegeta contra Cell en forma perfecta?",o:["Final Flash", "Kamehameha", "Makankosappo", "Dodonpa"],a:0,exp:"Vegeta usa el Final Flash contra Perfect Cell.",extra:"El ataque es tan poderoso que Cell lo evita parcialmente para no ser destruido por completo. Es uno de los momentos m\u00e1s imponentes de Vegeta."},
  {t:"m",q:"\u00bfQu\u00e9 ataque caracter\u00edstico usa Vegeta en su etapa Super Saiyajin contra Androide 19?",o:["Big Bang Attack", "Masenko", "Kienzan", "Death Beam"],a:0,exp:"Vegeta usa el Big Bang Attack para destruir a Androide 19.",extra:"La escena marca el debut de Vegeta como Super Saiyajin y uno de sus momentos de mayor arrogancia triunfal."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica de Krillin corta con un disco de energ\u00eda?",o:["Kienzan", "Dodonpa", "Masenko", "Final Shine"],a:0,exp:"El Kienzan es un disco de energ\u00eda cortante creado por Krillin.",extra:"Aunque Krillin no es de los m\u00e1s fuertes, el Kienzan es peligros\u00edsimo por su capacidad de cortar enemigos mucho m\u00e1s poderosos."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Tenshinhan para contener a Cell semi-perfecto?",o:["Kikoho", "Dodonpa", "Solar Flare", "Masenko"],a:0,exp:"Tenshinhan usa repetidamente el Kikoho para frenar a Cell.",extra:"La escena es memorable porque Tenshinhan, aunque superado en poder, usa toda su vida y energ\u00eda para ganar tiempo."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica ciega temporalmente al rival con luz intensa?",o:["Taiyoken", "Kaioken", "Kikoho", "Final Flash"],a:0,exp:"El Taiyoken, o Solar Flare, ciega temporalmente al oponente.",extra:"Es una t\u00e9cnica simple pero \u00fatil, usada por varios personajes para escapar o crear una oportunidad t\u00e1ctica."},
  {t:"m",q:"\u00bfQu\u00e9 raza alien\u00edgena cambia de forma y pertenece Freezer?",o:["Raza de Freezer", "Namekianos", "Saiyajin", "Yardrat"],a:0,exp:"La raza de Freezer no tiene un nombre oficial ampliamente establecido en la obra principal.",extra:"Los fans suelen llamarlos \u201craza de Freezer\u201d o \u201cdemonios del fr\u00edo\u201d, aunque ese \u00faltimo nombre viene m\u00e1s de materiales externos y videojuegos."},
  {t:"m",q:"\u00bfQui\u00e9n ense\u00f1a a Goku la teletransportaci\u00f3n instant\u00e1nea?",o:["Los Yardrat", "Kaio-sama", "Whis", "Korin"],a:0,exp:"Goku aprende la teletransportaci\u00f3n instant\u00e1nea en el planeta Yardrat.",extra:"La t\u00e9cnica permite moverse a cualquier ki conocido. Goku llega tarde a la Tierra tras Namek porque estuvo aprendiendo esta habilidad."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Dragon Ball original era un demonio verde que rejuvenece con las esferas?",o:["Piccolo Daimaoh", "Pilaf", "Tao Pai Pai", "General Blue"],a:0,exp:"Piccolo Daimaoh usa las Esferas del Drag\u00f3n para recuperar su juventud.",extra:"Fue uno de los primeros villanos realmente oscuros de Dragon Ball, marcando una transici\u00f3n hacia historias m\u00e1s serias."},
  {t:"m",q:"\u00bfQui\u00e9n es Tao Pai Pai?",o:["Un asesino de la Escuela Grulla", "Un androide", "Un namekiano", "Un saiyajin"],a:0,exp:"Tao Pai Pai es un asesino profesional relacionado con la Escuela Grulla.",extra:"Fue uno de los primeros enemigos que super\u00f3 claramente a Goku, oblig\u00e1ndolo a entrenar en la Torre de Karin."},
  {t:"m",q:"\u00bfQu\u00e9 ej\u00e9rcito combate Goku en su infancia?",o:["Ej\u00e9rcito Red Ribbon", "Fuerzas Ginyu", "Patrulla Gal\u00e1ctica", "Ej\u00e9rcito de Freezer"],a:0,exp:"Goku combate al Ej\u00e9rcito Red Ribbon durante la etapa cl\u00e1sica.",extra:"La importancia del Red Ribbon regresa a\u00f1os despu\u00e9s con el Dr. Gero, los androides y Cell."},
  {t:"m",q:"\u00bfQu\u00e9 androide amistoso conoce Goku de ni\u00f1o?",o:["Androide 8", "Androide 16", "Androide 17", "Androide 19"],a:0,exp:"Goku conoce al Androide 8, tambi\u00e9n llamado Hatchan.",extra:"Androide 8 es pac\u00edfico y bondadoso, contrastando con la visi\u00f3n militar del Ej\u00e9rcito Red Ribbon."},
  {t:"m",q:"\u00bfQui\u00e9n es el primer rival amoroso/c\u00f3mico de Goku por las Esferas del Drag\u00f3n?",o:["Pilaf", "Freezer", "Cell", "Garlic Jr."],a:0,exp:"Pilaf es uno de los primeros antagonistas c\u00f3micos de Dragon Ball.",extra:"Pilaf quiere dominar el mundo usando las Esferas del Drag\u00f3n, pero sus planes suelen fracasar de forma rid\u00edcula."},
  {t:"m",q:"\u00bfQu\u00e9 personaje cambia de personalidad al estornudar?",o:["Launch", "Bulma", "Chi-Chi", "Videl"],a:0,exp:"Launch cambia entre una personalidad dulce y otra agresiva al estornudar.",extra:"Launch fue importante en la etapa cl\u00e1sica, aunque desaparece casi por completo en Dragon Ball Z."},
  {t:"m",q:"\u00bfQui\u00e9n es la esposa de Goku?",o:["Bulma", "Chi-Chi", "Videl", "Launch"],a:1,exp:"Chi-Chi se casa con Goku despu\u00e9s de reencontrarlo en el torneo.",extra:"Su relaci\u00f3n nace de una promesa infantil que Goku no entend\u00eda bien. Chi-Chi suele preocuparse m\u00e1s por la educaci\u00f3n de Gohan que por las batallas."},
  {t:"m",q:"\u00bfQui\u00e9n es el padre de Chi-Chi?",o:["Ox-King", "Maestro Roshi", "Tao Pai Pai", "Mr. Satan"],a:0,exp:"Ox-King, o Gyumaoh, es el padre de Chi-Chi.",extra:"Fue alumno del Maestro Roshi junto con Son Gohan, el abuelo adoptivo de Goku."},
  {t:"m",q:"\u00bfQu\u00e9 torneo re\u00fane a los luchadores m\u00e1s fuertes de la Tierra?",o:["Tenkaichi Budokai", "Torneo de Poder", "Cell Games", "Torneo del Otro Mundo"],a:0,exp:"El Tenkaichi Budokai es el gran torneo de artes marciales de la Tierra.",extra:"En Dragon Ball cl\u00e1sico es el centro de varios arcos importantes y sirve para medir el crecimiento de Goku y sus rivales."},
  {t:"m",q:"\u00bfQui\u00e9n gana el 23\u00ba Tenkaichi Budokai?",o:["Goku", "Piccolo", "Tenshinhan", "Krillin"],a:0,exp:"Goku gana el 23\u00ba Tenkaichi Budokai derrotando a Piccolo Jr.",extra:"Esta victoria cierra la etapa cl\u00e1sica de Dragon Ball y deja a Goku como campe\u00f3n antes del salto hacia Dragon Ball Z."},
  {t:"m",q:"\u00bfQui\u00e9n es Piccolo Jr.?",o:["La reencarnaci\u00f3n/hijo de Piccolo Daimaoh", "Un saiyajin infiltrado", "Un androide namekiano", "Un Kaioshin ca\u00eddo"],a:0,exp:"Piccolo Jr. nace como la continuaci\u00f3n de Piccolo Daimaoh.",extra:"Aunque inicia como enemigo de Goku, termina cambiando gracias a Gohan y se convierte en uno de los aliados m\u00e1s confiables."},
  {t:"m",q:"\u00bfQu\u00e9 planeta era el hogar original de los saiyajin?",o:["Planeta Vegeta", "Planeta Namek", "Planeta Yardrat", "Planeta Sadala actual"],a:0,exp:"Los saiyajin del Universo 7 viv\u00edan en el planeta Vegeta.",extra:"Antes de llamarse as\u00ed, el planeta estaba habitado por los Tsufur y luego fue conquistado por los saiyajin."},
  {t:"m",q:"\u00bfQu\u00e9 forma alcanza Vegeta en Dragon Ball Super siguiendo su propio camino?",o:["Ultra Ego", "Ultra Instinto", "Super Saiyajin 4", "Mystic Vegeta"],a:0,exp:"Vegeta desarrolla Ultra Ego, una forma ligada al poder de los Dioses de la Destrucci\u00f3n.",extra:"Ultra Ego refleja la personalidad de Vegeta: crecer en combate, recibir da\u00f1o y convertir la batalla en orgullo destructivo."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Dragon Ball Super roba el cuerpo de Goku?",o:["Zamasu", "Hit", "Moro", "Granola"],a:0,exp:"Zamasu usa las Super Dragon Balls para intercambiar cuerpo con Goku, convirti\u00e9ndose en Goku Black.",extra:"El arco de Goku Black mezcla viajes temporales, justicia divina corrompida y una de las l\u00edneas futuras m\u00e1s desesperadas de la saga."},
  {t:"m",q:"\u00bfQu\u00e9 nombre usa Zamasu tras tomar el cuerpo de Goku?",o:["Goku Black", "Dark Goku", "Saiyajin Supremo", "Black Saiyan"],a:0,exp:"Zamasu en el cuerpo de Goku es conocido como Goku Black.",extra:"Su transformaci\u00f3n Super Saiyajin Ros\u00e9 es una variante divina del poder saiyajin en manos de un dios."},
  {t:"m",q:"\u00bfQu\u00e9 color caracteriza al Super Saiyajin Ros\u00e9?",o:["Dorado", "Azul", "Rosa", "Plateado"],a:2,exp:"El Super Saiyajin Ros\u00e9 se caracteriza por cabello rosado.",extra:"Es la forma usada por Goku Black y representa una versi\u00f3n divina de la transformaci\u00f3n Super Saiyajin."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Trunks del futuro como espada de energ\u00eda contra Zamasu fusionado?",o:["Espada de la Esperanza", "Final Flash", "Genkidama Blade", "Masenko Sword"],a:0,exp:"Trunks usa una espada cargada con energ\u00eda de esperanza para cortar a Zamasu fusionado.",extra:"La escena simboliza la resistencia de los sobrevivientes de su l\u00ednea temporal, aunque el desenlace del arco sigue siendo tr\u00e1gico."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Dragon Ball Super consume energ\u00eda vital de planetas?",o:["Moro", "Jiren", "Gas", "Broly"],a:0,exp:"Moro es un antiguo hechicero que absorbe energ\u00eda vital de planetas y seres vivos.",extra:"El arco de Moro, en el manga, recupera elementos m\u00e1gicos y de patrulla gal\u00e1ctica, mezclando combate con una amenaza m\u00e1s depredadora."},
  {t:"m",q:"\u00bfQu\u00e9 organizaci\u00f3n espacial aparece con Jaco?",o:["Patrulla Gal\u00e1ctica", "Ej\u00e9rcito de Freezer", "Fuerzas Ginyu", "Red Ribbon"],a:0,exp:"Jaco pertenece a la Patrulla Gal\u00e1ctica.",extra:"La Patrulla Gal\u00e1ctica expande el lado policial y espacial del universo Dragon Ball m\u00e1s all\u00e1 de Freezer y los saiyajin."},
  {t:"m",q:"\u00bfQui\u00e9n es Jaco?",o:["Un patrullero gal\u00e1ctico", "Un saiyajin \u00e9lite", "Un androide", "Un Kaioshin"],a:0,exp:"Jaco es un patrullero gal\u00e1ctico creado por Akira Toriyama.",extra:"Aunque es c\u00f3mico y algo presumido, conecta historias previas de Toriyama con Dragon Ball Super."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Dragon Ball Super desea convertirse en el guerrero m\u00e1s fuerte del universo?",o:["Granola", "Moro", "Zamasu", "Dabura"],a:0,exp:"Granola pide convertirse en el guerrero m\u00e1s fuerte usando las Esferas del Drag\u00f3n de Cereal.",extra:"Su historia est\u00e1 marcada por la venganza contra los saiyajin y Freezer, debido a la destrucci\u00f3n de su pueblo."},
  {t:"m",q:"\u00bfQu\u00e9 familia criminal manipula a Granola?",o:["Heeters", "Fuerzas Ginyu", "Red Ribbon", "Orgullo Troopers"],a:0,exp:"Los Heeters manipulan a Granola para sus propios objetivos.",extra:"Los Heeters son una familia criminal que busca ocupar el vac\u00edo de poder en el universo y superar a Freezer."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de los Heeters se vuelve extremadamente poderoso?",o:["Gas", "Elec", "Oil", "Macki"],a:0,exp:"Gas se convierte en el guerrero m\u00e1s fuerte mediante un deseo.",extra:"Su poder tiene un coste enorme, y su arco muestra los peligros de obtener fuerza artificialmente sin libertad propia."},
  {t:"m",q:"\u00bfQu\u00e9 forma reciente de Freezer supera a Goku y Vegeta en el manga?",o:["Black Freezer", "Golden Freezer", "Platinum Freezer", "Final Freezer"],a:0,exp:"Freezer revela la forma Black Freezer tras entrenar en una habitaci\u00f3n del tiempo.",extra:"La aparici\u00f3n de Black Freezer vuelve a colocar a Freezer como una amenaza superior, incluso despu\u00e9s de todos los avances divinos de Goku y Vegeta."},
  {t:"m",q:"\u00bfQu\u00e9 pel\u00edcula introduce a Gamma 1 y Gamma 2?",o:["Dragon Ball Super: Super Hero", "Dragon Ball Super: Broly", "Resurrection F", "Battle of Gods"],a:0,exp:"Gamma 1 y Gamma 2 aparecen en Dragon Ball Super: Super Hero.",extra:"Son androides creados por el nuevo Red Ribbon y se presentan como superh\u00e9roes desde su propia perspectiva."},
  {t:"m",q:"\u00bfQu\u00e9 transformaci\u00f3n obtiene Piccolo en Dragon Ball Super: Super Hero?",o:["Orange Piccolo", "Super Namek God", "Piccolo Blue", "Kami Mode"],a:0,exp:"Piccolo obtiene la forma Orange Piccolo.",extra:"Esta transformaci\u00f3n devuelve a Piccolo un papel de primera l\u00ednea en combate y reconoce su importancia hist\u00f3rica en la saga."},
  {t:"m",q:"\u00bfQu\u00e9 nueva forma despierta Gohan en Super Hero?",o:["Gohan Beast", "Ultra Gohan", "Mystic 2", "Saiyaman Final"],a:0,exp:"Gohan despierta la forma Gohan Beast.",extra:"La transformaci\u00f3n evoca su despertar contra Cell, con furia protectora y un poder que vuelve a ponerlo entre los guerreros m\u00e1s fuertes."},
  {t:"m",q:"\u00bfQu\u00e9 criatura revive el Red Ribbon como amenaza final en Super Hero?",o:["Cell Max", "Perfect Cell", "Majin Cell", "Android 21"],a:0,exp:"Cell Max es la amenaza final de Dragon Ball Super: Super Hero.",extra:"No es el Cell original con su personalidad completa, sino una bioarma incompleta y descontrolada inspirada en Cell."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de videojuegos est\u00e1 asociada a Dragon Ball FighterZ?",o:["Android 21", "Launch", "Maron", "Fasha"],a:0,exp:"Android 21 es un personaje original de Dragon Ball FighterZ.",extra:"Su dise\u00f1o fue supervisado por Akira Toriyama y se volvi\u00f3 muy popular por su conexi\u00f3n con androides, Majin y ciencia del Red Ribbon."},
  {t:"m",q:"\u00bfQu\u00e9 estudio anim\u00f3 hist\u00f3ricamente Dragon Ball en televisi\u00f3n?",o:["Toei Animation", "Studio Ghibli", "Madhouse", "Bones"],a:0,exp:"Toei Animation produjo las adaptaciones animadas principales de Dragon Ball.",extra:"Toei fue responsable de Dragon Ball, Dragon Ball Z, Dragon Ball GT y Dragon Ball Super, adem\u00e1s de m\u00faltiples pel\u00edculas."},
  {t:"m",q:"\u00bfQui\u00e9n cre\u00f3 el manga Dragon Ball?",o:["Akira Toriyama", "Masashi Kishimoto", "Eiichiro Oda", "Yoshihiro Togashi"],a:0,exp:"Dragon Ball fue creado por Akira Toriyama.",extra:"Toriyama ya era famoso por Dr. Slump antes de Dragon Ball. Su estilo de humor, aventura y dise\u00f1o mec\u00e1nico dej\u00f3 una huella enorme en el manga y el anime."},
  {t:"m",q:"\u00bfQu\u00e9 obra china inspir\u00f3 parcialmente el inicio de Dragon Ball?",o:["Viaje al Oeste", "Romance de los Tres Reinos", "El arte de la guerra", "La leyenda de Mulan"],a:0,exp:"Dragon Ball se inspira parcialmente en Viaje al Oeste.",extra:"Goku est\u00e1 inspirado en Sun Wukong: tiene cola de mono, bast\u00f3n m\u00e1gico, nube voladora y una personalidad inicialmente salvaje."},
  {t:"m",q:"\u00bfQu\u00e9 bast\u00f3n m\u00e1gico usa Goku de ni\u00f1o?",o:["Nyoibo", "Z Sword", "Power Pole", "Las dos primeras no"],a:0,exp:"El bast\u00f3n de Goku se llama Nyoibo en japon\u00e9s, conocido tambi\u00e9n como Power Pole.",extra:"Puede extenderse enormemente y conecta simb\u00f3licamente el mundo terrenal con el templo de Kami-sama."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Goku para leer la mente de Krillin en Namek?",o:["Telepat\u00eda tocando la cabeza", "Haki", "Ultra Instinto", "Kaioken mental"],a:0,exp:"Goku lee la mente de Krillin toc\u00e1ndole la cabeza al llegar a Namek.",extra:"Es una habilidad poco usada despu\u00e9s, pero muestra que el ki y el entrenamiento de Goku incluyen capacidades m\u00e1s all\u00e1 de lanzar energ\u00eda."},
  {t:"m",q:"\u00bfQu\u00e9 villano de pel\u00edcula se fusiona con las Esferas del Drag\u00f3n en GT como drag\u00f3n maligno final?",o:["Omega Shenron", "Baby", "Super 17", "Janemba"],a:0,exp:"Omega Shenron es el drag\u00f3n maligno final de Dragon Ball GT.",extra:"Representa la consecuencia negativa de abusar de los deseos de las Esferas del Drag\u00f3n, una idea muy interesante dentro del lore de GT."},
  {t:"m",q:"\u00bfQu\u00e9 transformaci\u00f3n ic\u00f3nica aparece en Dragon Ball GT?",o:["Super Saiyajin 4", "Super Saiyajin Blue", "Ultra Ego", "Super Saiyajin Ros\u00e9"],a:0,exp:"Dragon Ball GT introduce el Super Saiyajin 4.",extra:"A diferencia de las formas divinas modernas, el Super Saiyajin 4 conecta con el lado m\u00e1s salvaje del saiyajin: cola, Ozaru y control consciente del poder primitivo."},
  {t:"m",q:"\u00bfQu\u00e9 villano de GT posee cuerpos y busca venganza contra los saiyajin?",o:["Baby", "Moro", "Zamasu", "Babidi"],a:0,exp:"Baby es un par\u00e1sito creado por los Tsufur que busca vengarse de los saiyajin.",extra:"Su odio nace del exterminio de su pueblo por los saiyajin, haciendo que GT explore las consecuencias hist\u00f3ricas de la raza de Goku y Vegeta."},
  {t:"m",q:"\u00bfQu\u00e9 fusi\u00f3n aparece en GT al combinar Super Saiyajin 4 de Goku y Vegeta?",o:["Gogeta Super Saiyajin 4", "Vegito Blue", "Gotenks 4", "Gokhan"],a:0,exp:"Goku y Vegeta se fusionan en Gogeta Super Saiyajin 4.",extra:"Es una de las formas m\u00e1s populares de GT, aunque su personalidad juguetona hace que desperdicie tiempo contra Omega Shenron."},
  {t:"m",q:"\u00bfQu\u00e9 villano de pel\u00edcula tiene poderes relacionados con una dimensi\u00f3n infernal y se llama Janemba?",o:["Janemba", "Hirudegarn", "Cooler", "Slug"],a:0,exp:"Janemba es el villano de la pel\u00edcula Fusion Reborn.",extra:"Su dise\u00f1o y poderes de distorsi\u00f3n espacial lo hicieron muy popular, especialmente porque la pel\u00edcula presenta a Gogeta."},
  {t:"m",q:"\u00bfQui\u00e9n es Cooler?",o:["Hermano de Freezer", "Padre de Freezer", "Un androide", "Un Kaioshin oscuro"],a:0,exp:"Cooler es el hermano de Freezer en pel\u00edculas no can\u00f3nicas cl\u00e1sicas.",extra:"Aunque no pertenece a la continuidad principal original, Cooler se volvi\u00f3 muy querido por su dise\u00f1o y transformaciones."},
  {t:"m",q:"\u00bfQui\u00e9n es el padre de Freezer?",o:["King Cold", "Cooler", "Chilled", "Frost"],a:0,exp:"King Cold es el padre de Freezer.",extra:"Aparece junto a Mecha Freezer al llegar a la Tierra, pero ambos son eliminados r\u00e1pidamente por Trunks del futuro."},
  {t:"m",q:"\u00bfQu\u00e9 personaje del Universo 6 se parece a Freezer?",o:["Frost", "Hit", "Cabba", "Magetta"],a:0,exp:"Frost es un miembro de la raza de Freezer en el Universo 6.",extra:"Al principio parece noble, pero se revela como manipulador y tramposo, jugando con las expectativas del p\u00fablico."},
  {t:"m",q:"\u00bfQu\u00e9 robot met\u00e1lico del Universo 6 lucha contra Vegeta?",o:["Magetta", "Botamo", "Hit", "Dyspo"],a:0,exp:"Magetta es un Metalman del Universo 6 que pelea contra Vegeta.",extra:"Su especie es muy resistente, pero emocionalmente vulnerable a insultos, algo que Vegeta explota en combate."},
  {t:"m",q:"\u00bfQu\u00e9 personaje del Universo 11 lidera los Pride Troopers?",o:["Toppo", "Jiren", "Dyspo", "Belmod"],a:0,exp:"Toppo es l\u00edder de los Pride Troopers.",extra:"Toppo tambi\u00e9n es candidato a Dios de la Destrucci\u00f3n, lo que revela su enorme poder y sentido de justicia."},
  {t:"m",q:"\u00bfQu\u00e9 Pride Trooper es famoso por su velocidad?",o:["Dyspo", "Toppo", "Jiren", "Kahseral"],a:0,exp:"Dyspo es conocido por su velocidad extrema.",extra:"Su estilo recuerda a un velocista c\u00f3smico, obligando a rivales como Hit, Gohan y Freezer a usar estrategia para contenerlo."},
  {t:"m",q:"\u00bfQu\u00e9 universo gana protagonismo como rival del Universo 7 en el primer torneo de Super?",o:["Universo 6", "Universo 11", "Universo 2", "Universo 10"],a:0,exp:"El Universo 6 compite contra el Universo 7 en el torneo organizado por Bills y Champa.",extra:"Este torneo introduce versiones alternativas de razas conocidas, como saiyajin pac\u00edficos y un equivalente de Freezer llamado Frost."},
  {t:"m",q:"\u00bfQui\u00e9n es el Dios de la Destrucci\u00f3n del Universo 6?",o:["Champa", "Bills", "Belmod", "Sidra"],a:0,exp:"Champa es el Dios de la Destrucci\u00f3n del Universo 6.",extra:"Champa es hermano de Bills y comparte con \u00e9l una rivalidad c\u00f3mica centrada en comida, orgullo y competencias absurdas."},
  {t:"m",q:"\u00bfQui\u00e9n es la \u00e1ngel asistente de Champa?",o:["Vados", "Whis", "Marcarita", "Cus"],a:0,exp:"Vados es la \u00e1ngel asistente de Champa.",extra:"Vados es hermana de Whis y suele burlarse de Champa por su falta de disciplina f\u00edsica."},
  {t:"m",q:"\u00bfQu\u00e9 planeta es el hogar de los saiyajin del Universo 6?",o:["Sadala", "Vegeta", "Vampa", "Namek"],a:0,exp:"Los saiyajin del Universo 6 viven en el planeta Sadala.",extra:"A diferencia de los saiyajin del Universo 7, los del Universo 6 no son conquistadores brutales, sino protectores contratados."},
  {t:"m",q:"\u00bfC\u00f3mo se llama el planeta donde Broly vive exiliado en Dragon Ball Super: Broly?",o:["Vampa", "Namek", "Sadala", "Yardrat"],a:0,exp:"Broly vive exiliado en el planeta Vampa.",extra:"Vampa es un mundo hostil lleno de criaturas peligrosas, donde Broly sobrevive junto a Paragus durante a\u00f1os."},
  {t:"m",q:"\u00bfQu\u00e9 deseo pide Freezer al final de Dragon Ball Super: Broly?",o:["Ser cinco cent\u00edmetros m\u00e1s alto", "Ser inmortal", "Destruir la Tierra", "Controlar a Broly"],a:0,exp:"Freezer quer\u00eda pedir ser cinco cent\u00edmetros m\u00e1s alto.",extra:"El detalle es c\u00f3mico porque Freezer quiere que el cambio parezca natural, mostrando su vanidad incluso despu\u00e9s de alcanzar poderes enormes."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Whis para retroceder brevemente el tiempo en Resurrection F?",o:["Rebobinado temporal", "Kaioken divino", "Anulaci\u00f3n angelical", "Chrono Shift"],a:0,exp:"Whis puede retroceder el tiempo unos segundos.",extra:"Esta habilidad permite corregir la destrucci\u00f3n de la Tierra causada por Freezer, aunque Whis advierte que no debe abusarse de ella."},
  {t:"m",q:"\u00bfQui\u00e9n destruye la Tierra en Resurrection F antes del rebobinado de Whis?",o:["Freezer", "Bills", "Goku", "Vegeta"],a:0,exp:"Freezer destruye la Tierra cuando se ve acorralado.",extra:"Es una muestra de su crueldad y orgullo: si no puede ganar, prefiere destruir el tablero entero."},
  {t:"m",q:"\u00bfQu\u00e9 personaje pierde la oportunidad de matar a Freezer por demorarse?",o:["Vegeta", "Gohan", "Piccolo", "Trunks"],a:0,exp:"Vegeta demora demasiado y Freezer aprovecha para destruir la Tierra.",extra:"La escena subraya uno de los defectos cl\u00e1sicos de Vegeta: su tendencia a saborear demasiado la victoria."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Dragon Ball cl\u00e1sico es un conejo que convierte personas en zanahoria?",o:["Monster Carrot", "Pilaf", "Oolong", "Shu"],a:0,exp:"Monster Carrot puede convertir personas en zanahoria al tocarlas.",extra:"Es uno de los villanos absurdos de la etapa temprana de Dragon Ball, cuando el tono era mucho m\u00e1s humor\u00edstico y fant\u00e1stico."},
  {t:"m",q:"\u00bfQu\u00e9 compa\u00f1ero de Pilaf es una ninja femenina?",o:["Mai", "Launch", "Videl", "Maron"],a:0,exp:"Mai forma parte de la banda de Pilaf junto a Shu.",extra:"En Dragon Ball Super, una versi\u00f3n rejuvenecida de Mai tiene un v\u00ednculo importante con Trunks del futuro."},
  {t:"m",q:"\u00bfQu\u00e9 animal cambiaformas acompa\u00f1a a Yamcha?",o:["Puar", "Oolong", "Korin", "Shu"],a:0,exp:"Puar acompa\u00f1a a Yamcha desde la etapa cl\u00e1sica.",extra:"Puar puede transformarse, igual que Oolong, y es uno de los personajes c\u00f3micos m\u00e1s antiguos de la saga."},
  {t:"m",q:"\u00bfQu\u00e9 personaje puede transformarse pero suele ser cobarde y pervertido?",o:["Oolong", "Puar", "Shu", "Korin"],a:0,exp:"Oolong es un cerdo cambiaformas con personalidad cobarde y c\u00f3mica.",extra:"Oolong salva al mundo al pedir unas bragas como deseo antes de que Pilaf pueda pedir dominar el mundo."},
  {t:"m",q:"\u00bfCu\u00e1l fue el primer deseo concedido por Shenlong en la serie?",o:["Unas bragas", "La inmortalidad", "Revive a Krillin", "Un castillo"],a:0,exp:"Oolong pide unas bragas, arruinando el deseo de Pilaf.",extra:"Es una escena que resume el tono original de Dragon Ball: aventura fant\u00e1stica mezclada con humor absurdo."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica usa Goku para vencer a Piccolo Daimaoh atraves\u00e1ndolo?",o:["Pu\u00f1o del drag\u00f3n", "Kamehameha inverso y golpe final", "Kaioken", "Genkidama"],a:1,exp:"Goku usa un Kamehameha para impulsarse y atravesar a Piccolo Daimaoh con un golpe.",extra:"Es una de las victorias m\u00e1s f\u00edsicas y desesperadas de Goku en la etapa cl\u00e1sica."},
  {t:"m",q:"\u00bfQui\u00e9n mata a Krillin por primera vez?",o:["Tambourine", "Freezer", "Cell", "Nappa"],a:0,exp:"Tambourine, hijo de Piccolo Daimaoh, mata a Krillin en Dragon Ball cl\u00e1sico.",extra:"Esa muerte cambia el tono de la serie, mostrando que incluso personajes queridos pod\u00edan morir de forma repentina."},
  {t:"m",q:"\u00bfQu\u00e9 villano absorbe androides con su cola?",o:["Cell", "Buu", "Moro", "Baby"],a:0,exp:"Cell absorbe a 17 y 18 usando su cola.",extra:"Su dise\u00f1o cambia con cada absorci\u00f3n, pasando de una forma insectoide imperfecta a una forma perfecta m\u00e1s humana y arrogante."},
  {t:"m",q:"\u00bfQu\u00e9 androide ama la naturaleza y evita pelear innecesariamente?",o:["Androide 16", "Androide 17", "Androide 18", "Androide 19"],a:0,exp:"Androide 16 es pac\u00edfico y ama la naturaleza, aunque fue creado para matar a Goku.",extra:"Su muerte frente a Gohan es el detonante emocional para el Super Saiyajin 2."},
  {t:"m",q:"\u00bfQu\u00e9 personaje lanza la cabeza del Androide 16 hacia Gohan?",o:["Mr. Satan", "Cell", "Krillin", "Trunks"],a:0,exp:"Mr. Satan arroja la cabeza del Androide 16 cerca de Gohan.",extra:"Aunque lo hace de manera torpe, esa acci\u00f3n permite que 16 d\u00e9 su \u00faltimo mensaje a Gohan antes de ser destruido por Cell."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Z absorbe personas para cambiar de forma y personalidad?",o:["Majin Buu", "Freezer", "Cell", "Raditz"],a:0,exp:"Majin Buu absorbe personas, incorporando sus poderes y rasgos.",extra:"Al absorber a Gotenks, Piccolo y Gohan, Buu se vuelve mucho m\u00e1s inteligente y peligroso."},
  {t:"m",q:"\u00bfQu\u00e9 versi\u00f3n de Buu se vuelve amiga de Mr. Satan?",o:["Buu gordo", "Super Buu", "Kid Buu", "Buuhan"],a:0,exp:"El Buu gordo desarrolla una amistad genuina con Mr. Satan.",extra:"Esa amistad ayuda a separar su lado malvado y demuestra que Buu no era pura maldad desde el inicio."},
  {t:"m",q:"\u00bfC\u00f3mo se llama el perro amigo de Majin Buu y Mr. Satan?",o:["Bee", "Puar", "Icarus", "Bubbles"],a:0,exp:"El perro se llama Bee.",extra:"El v\u00ednculo con Bee y Mr. Satan humaniza a Majin Buu y cambia el curso de la saga."},
  {t:"m",q:"\u00bfQu\u00e9 mono vive con Kaio-sama?",o:["Bubbles", "Korin", "Gregory", "Puar"],a:0,exp:"Bubbles es el mono de Kaio-sama.",extra:"Goku debe atraparlo como parte de su entrenamiento en alta gravedad en el planeta de Kaio-sama."},
  {t:"m",q:"\u00bfQu\u00e9 peque\u00f1a criatura con martillo aparece en el anime junto a Kaio-sama?",o:["Gregory", "Bubbles", "Korin", "Bee"],a:0,exp:"Gregory aparece en el anime como parte del entrenamiento de Goku con Kaio-sama.",extra:"Goku debe golpearlo con un martillo, lo que entrena su velocidad y adaptaci\u00f3n a la gravedad del planeta."},
  {t:"m",q:"\u00bfQu\u00e9 gravedad tiene el planeta de Kaio-sama?",o:["10 veces la de la Tierra", "50 veces", "100 veces", "500 veces"],a:0,exp:"El planeta de Kaio-sama tiene una gravedad 10 veces mayor que la Tierra.",extra:"Esa gravedad es similar a la del planeta Vegeta, ayudando a explicar por qu\u00e9 los saiyajin tienen cuerpos tan resistentes."},
  {t:"m",q:"\u00bfQu\u00e9 sala permite entrenar durante un a\u00f1o mientras afuera pasa un d\u00eda?",o:["Habitaci\u00f3n del Tiempo", "C\u00e1mara de Gravedad", "Templo Kai", "Sala del Drag\u00f3n"],a:0,exp:"La Habitaci\u00f3n del Tiempo permite entrenar un a\u00f1o dentro mientras afuera pasa un d\u00eda.",extra:"Tambi\u00e9n tiene condiciones extremas de temperatura, gravedad y espacio, por eso no es solo una ventaja temporal sino una prueba f\u00edsica y mental."},
  {t:"m",q:"\u00bfQui\u00e9n usa primero la c\u00e1mara de gravedad construida por Capsule Corp de forma obsesiva?",o:["Vegeta", "Goku", "Gohan", "Trunks"],a:0,exp:"Vegeta entrena obsesivamente en la c\u00e1mara de gravedad de Capsule Corp.",extra:"Su deseo de superar a Goku lo lleva a entrenar bajo condiciones brutales, especialmente antes de alcanzar el Super Saiyajin."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica permite a los guerreros ocultar o aumentar su energ\u00eda?",o:["Control del ki", "Scouter", "Fusi\u00f3n", "Absorci\u00f3n"],a:0,exp:"El control del ki permite esconder, elevar o concentrar energ\u00eda.",extra:"Los saiyajin y soldados de Freezer dependen mucho de scouters al principio, pero los guerreros terrestres saben alterar su ki, sorprendiendo a los invasores."},
  {t:"m",q:"\u00bfQu\u00e9 dispositivo mide el poder de pelea?",o:["Scouter", "Radar del drag\u00f3n", "Pothala", "Detector Kai"],a:0,exp:"Los scouters miden el poder de pelea de un objetivo.",extra:"Se vuelven s\u00edmbolos de la saga saiyajin y Freezer, aunque pronto quedan obsoletos porque muchos guerreros pueden ocultar o explotar su poder repentinamente."},
  {t:"m",q:"\u00bfQu\u00e9 famosa frase se asocia al poder de Goku contra Vegeta en el doblaje ingl\u00e9s?",o:["It\u2019s over 9000!", "Final Flash!", "I am the hope!", "Kakarot wins!"],a:0,exp:"\u201cIt\u2019s over 9000!\u201d se volvi\u00f3 una de las frases m\u00e1s famosas del doblaje ingl\u00e9s.",extra:"En algunas versiones japonesas el n\u00famero era 8000, pero el doblaje ingl\u00e9s convirti\u00f3 \u201cover 9000\u201d en meme mundial."},
  {t:"m",q:"\u00bfQu\u00e9 grupo especial de Freezer hace poses dram\u00e1ticas?",o:["Fuerzas Ginyu", "Orgullo Troopers", "Red Ribbon", "Heeters"],a:0,exp:"Las Fuerzas Ginyu son el escuadr\u00f3n especial de \u00e9lite de Freezer.",extra:"Son poderosos, pero tambi\u00e9n rid\u00edculamente teatrales. Sus poses sentaron una tradici\u00f3n par\u00f3dica dentro de Dragon Ball."},
  {t:"m",q:"\u00bfQu\u00e9 habilidad especial tiene el Capit\u00e1n Ginyu?",o:["Cambiar de cuerpo", "Detener el tiempo", "Convertir en chocolate", "Controlar gravedad"],a:0,exp:"Ginyu puede intercambiar cuerpos con su t\u00e9cnica Body Change.",extra:"La usa contra Goku en Namek, pero termina atrapado en el cuerpo de una rana por una cadena de errores."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de las Fuerzas Ginyu puede detener el tiempo conteniendo la respiraci\u00f3n?",o:["Guldo", "Recoome", "Burter", "Jeice"],a:0,exp:"Guldo puede detener el tiempo mientras aguanta la respiraci\u00f3n.",extra:"Aunque es f\u00edsicamente el m\u00e1s d\u00e9bil del grupo, su habilidad es muy peligrosa si se usa con estrategia."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de las Fuerzas Ginyu es famoso por su resistencia y brutalidad contra Vegeta, Krillin y Gohan?",o:["Recoome", "Guldo", "Jeice", "Burter"],a:0,exp:"Recoome derrota brutalmente a Vegeta, Krillin y Gohan antes de la llegada de Goku.",extra:"Su pelea sirve para mostrar el salto enorme de poder que Goku obtuvo entrenando durante el viaje a Namek."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica caracter\u00edstica usa Gohan de ni\u00f1o?",o:["Masenko", "Final Flash", "Destructo Disc", "Galick Gun"],a:0,exp:"Gohan usa el Masenko, t\u00e9cnica aprendida de Piccolo.",extra:"El Masenko refleja la influencia de Piccolo como maestro, diferenciando el estilo de Gohan del de Goku."},
  {t:"m",q:"\u00bfQu\u00e9 ataque usa Vegeta contra el Kamehameha de Goku en la saga saiyajin?",o:["Galick Gun", "Final Flash", "Big Bang Attack", "Death Beam"],a:0,exp:"Vegeta usa el Galick Gun contra el Kamehameha aumentado con Kaioken de Goku.",extra:"El choque de ambos ataques es uno de los primeros grandes duelos de energ\u00eda de Dragon Ball Z."},
  {t:"m",q:"\u00bfQu\u00e9 personaje es conocido por morir de forma famosa contra un Saibaman?",o:["Yamcha", "Krillin", "Tenshinhan", "Yajirobe"],a:0,exp:"Yamcha muere cuando un Saibaman se autodestruye agarrado a \u00e9l.",extra:"La escena se volvi\u00f3 meme durante d\u00e9cadas, aunque en contexto mostraba lo peligrosos que eran incluso los soldados plantados por Nappa."},
  {t:"m",q:"\u00bfQu\u00e9 son los Saibaman?",o:["Criaturas cultivadas desde semillas para combatir", "Androides peque\u00f1os", "Namekianos corruptos", "Soldados de Freezer"],a:0,exp:"Los Saibaman son criaturas biol\u00f3gicas que crecen desde semillas plantadas en el suelo.",extra:"Nappa y Vegeta los usan para probar a los guerreros terrestres antes de pelear personalmente."},
  {t:"m",q:"\u00bfQu\u00e9 personaje usa la t\u00e9cnica Dodonpa?",o:["Tao Pai Pai", "Goku", "Vegeta", "Freezer"],a:0,exp:"Tao Pai Pai y la Escuela Grulla usan el Dodonpa.",extra:"El Dodonpa es una t\u00e9cnica de rayo concentrado que compite conceptualmente con el Kamehameha de la Escuela Tortuga."},
  {t:"m",q:"\u00bfQui\u00e9n es el maestro de Tenshinhan y Chaoz al inicio?",o:["Maestro Tsuru", "Maestro Roshi", "Korin", "Kami-sama"],a:0,exp:"Tenshinhan y Chaoz fueron alumnos del Maestro Tsuru.",extra:"El Maestro Tsuru, hermano de Tao Pai Pai, representa una escuela rival y m\u00e1s cruel que la Escuela Tortuga."},
  {t:"m",q:"\u00bfQu\u00e9 personaje abandona el camino de asesino para volverse aliado de Goku?",o:["Tenshinhan", "Freezer", "Dabura", "Cell"],a:0,exp:"Tenshinhan abandona la influencia de la Escuela Grulla y se vuelve aliado de Goku.",extra:"Su cambio es uno de los primeros ejemplos de rivales que Dragon Ball transforma en compa\u00f1eros, patr\u00f3n que luego se repite con Piccolo y Vegeta."},
  {t:"m",q:"\u00bfQu\u00e9 personaje se convierte de villano principal a uno de los h\u00e9roes m\u00e1s importantes?",o:["Vegeta", "Freezer", "Cell", "Babidi"],a:0,exp:"Vegeta pasa de villano saiyajin a aliado central y protector de la Tierra.",extra:"Su evoluci\u00f3n es una de las m\u00e1s largas de la saga: orgullo, rivalidad, familia, sacrificio y b\u00fasqueda de un camino propio."},
  {t:"m",q:"\u00bfCu\u00e1ntos universos existen en Dragon Ball Super?",o:["12","7","18","9"],a:0,exp:"Dragon Ball Super establece la existencia de doce universos.",extra:"Cada universo tiene un Dios de la Destrucci\u00f3n, un \u00c1ngel asistente y un Supremo Kai. Los universos con bajo \u00edndice de mortales son amenazados con ser borrados por Zeno."},
  {t:"m",q:"\u00bfQu\u00e9 Dios de la Destrucci\u00f3n corresponde al Universo 11, el universo de Jiren?",o:["Belmod","Sidra","Quitela","Mosco"],a:0,exp:"Belmod es el Dios de la Destrucci\u00f3n del Universo 11.",extra:"Belmod tiene apariencia de payaso y es el mentor de Jiren, aunque la relaci\u00f3n entre ambos revela aspectos de la historia personal de Jiren."},
  {t:"m",q:"\u00bfQu\u00e9 \u00c1ngel es el asistente de Belmod en el Universo 11?",o:["Marcarita","Vados","Cus","Korn"],a:0,exp:"Marcarita es la \u00c1ngel del Universo 11.",extra:"Los \u00c1ngeles son hijos del Daishinkan y hermanos entre s\u00ed. Todos superan en poder a los Dioses de la Destrucci\u00f3n a quienes asisten."},
  {t:"m",q:"\u00bfQu\u00e9 Dios de la Destrucci\u00f3n del Universo 9 intent\u00f3 eliminar al Universo 7 con esferas envenenadas?",o:["Sidra","Quitela","Roh","Mosco"],a:0,exp:"Sidra es el Dios de la Destrucci\u00f3n del Universo 9.",extra:"Junto al Supremo Kai Roh, intentaron eliminar a Freezer usando bolas de destrucci\u00f3n, pero el plan fracas\u00f3."},
  {t:"m",q:"\u00bfQui\u00e9n es el Daishinkan en Dragon Ball Super?",o:["El gran sacerdote y padre de los \u00c1ngeles","El dios creador del multiverso","El asistente personal de Zeno","El Supremo Kai m\u00e1s poderoso"],a:0,exp:"El Daishinkan es el Gran Sacerdote, padre de los \u00c1ngeles y consejero principal de Zeno.",extra:"Su poder supera al de todos los Dioses de la Destrucci\u00f3n y posiblemente es el ser m\u00e1s poderoso despu\u00e9s del propio Zeno."},
  {t:"m",q:"\u00bfQu\u00e9 versi\u00f3n futura de Zamasu se fusiona consigo mismo del pasado con los Pendientes Pothala?",o:["Zamasu fusionado","Black Zamasu","Infinite Zamasu","Merged Zamasu"],a:0,exp:"Zamasu del futuro usa los Pendientes Pothala para fusionarse con Goku Black, creando a Zamasu fusionado.",extra:"Su cuerpo medio mortal y medio inmortal crea una paradoja que termina haciendo que su cuerpo se desintegre pero su alma llene el cielo del futuro."},
  {t:"m",q:"\u00bfQu\u00e9 versi\u00f3n de Trunks del futuro usa una t\u00e9cnica de espada de luz al final del arco de Zamasu?",o:["Trunks del futuro con la Espada de la Esperanza","Trunks Super Saiyajin Rage","Super Trunks Final","Trunks SSJ Dios"],a:0,exp:"Trunks del futuro crea una espada de energ\u00eda pura combinando su ki con la esperanza de la gente para cortar a Zamasu fusionado.",extra:"La forma se conoce como Super Saiyajin Ira o Rage, una transformaci\u00f3n \u00fanica de Trunks impulsada por furia y desesperaci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 villano del arco de Moro puede absorber el ki y la vida de planetas enteros?",o:["Moro","Gas","Granola","Heeter"],a:0,exp:"Moro el devorador de planetas absorbe energ\u00eda vital de mundos y seres vivos.",extra:"Su poder m\u00e1gico lo hace resistente al ki convencional, obligando a Goku a buscar el Ultra Instinto Completo para enfrentarlo."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de la Patrulla Gal\u00e1ctica es aliado c\u00f3mico de Goku en el arco de Moro?",o:["Jaco","Merus","Granola","Irico"],a:0,exp:"Jaco es el patrullero gal\u00e1ctico c\u00f3mico que reaparece frecuentemente en Dragon Ball Super.",extra:"Creado originalmente en el manga independiente Jaco the Galactic Patrolman de Toriyama, se integr\u00f3 al universo Dragon Ball Super."},
  {t:"m",q:"\u00bfQu\u00e9 \u00e1ngel entren\u00f3 a Goku en secreto mientras operaba como Patrullero Gal\u00e1ctico?",o:["Merus","Whis","Vados","Marcarita"],a:0,exp:"Merus es un \u00e1ngel que opera encubierto como oficial de la Patrulla Gal\u00e1ctica.",extra:"Entrena a Goku para dominar el Ultra Instinto. Al intervenir directamente en combate, viola las reglas ang\u00e9licas y es borrado, aunque luego es restaurado."},
  {t:"m",q:"\u00bfQu\u00e9 diferencia principal existe entre Dragon Ball GT y Dragon Ball Super en cuanto a canonicidad?",o:["GT no es canon; Super s\u00ed es oficial","GT es canon; Super no lo es","Ambos son canon por igual","Ninguno es considerado canon"],a:0,exp:"Dragon Ball GT no es considerado canon por Akira Toriyama; Dragon Ball Super s\u00ed es obra oficial de Toriyama.",extra:"GT fue producido por Toei Animation sin la participaci\u00f3n directa de Toriyama como guionista. Super es el continuador oficial de la historia."},
  {t:"m",q:"\u00bfQu\u00e9 transformaci\u00f3n exclusiva de GT conecta la forma primitiva del Ozaru con la consciencia del Super Saiyajin?",o:["Super Saiyajin 4","Super Saiyajin 3 Ozaru","Golden Ozaru Controlado","Primal Super Saiyajin"],a:0,exp:"El Super Saiyajin 4 fusiona el control del Super Saiyajin con el poder del Ozaru dorado.",extra:"A diferencia de las formas divinas de Super, el SS4 tiene cabello negro y pelo rojo oscuro en el cuerpo, con una est\u00e9tica muy diferente a las transformaciones posteriores."},
  {t:"m",q:"\u00bfQu\u00e9 videojuego de Dragon Ball permite crear personajes propios y viajar por la historia?",o:["Dragon Ball Xenoverse","Dragon Ball FighterZ","Dragon Ball Kakarot","Dragon Ball Legends"],a:0,exp:"Dragon Ball Xenoverse permite al jugador crear un personaje de varias razas y viajar por la historia modific\u00e1ndola.",extra:"La saga Xenoverse tiene dos entregas principales y un lore propio sobre la Patrulla del Tiempo que se volvi\u00f3 muy popular entre la comunidad."},
  {t:"m",q:"\u00bfQu\u00e9 videojuego de Dragon Ball es un RPG de acci\u00f3n que sigue la historia de Goku desde el inicio?",o:["Dragon Ball Z: Kakarot","Dragon Ball Xenoverse","Dragon Ball FighterZ","Dragon Ball Budokai Tenkaichi"],a:0,exp:"Dragon Ball Z: Kakarot es un RPG de acci\u00f3n que narra la historia de Goku a lo largo de Dragon Ball Z.",extra:"Incluye misiones secundarias, coleccionables y momentos de vida cotidiana entre sagas. Tambi\u00e9n tuvo DLCs de Dragon Ball Super."},
  {t:"m",q:"\u00bfQu\u00e9 videojuego de Dragon Ball es conocido por su sistema de combate 2D con alta fidelidad visual?",o:["Dragon Ball FighterZ","Dragon Ball Xenoverse","Dragon Ball Z Budokai","Dragon Ball Legends"],a:0,exp:"Dragon Ball FighterZ es un juego de lucha 2D desarrollado por Arc System Works con gr\u00e1ficos de alta calidad.",extra:"Presenta un modo historia original con el personaje Android 21 dise\u00f1ado por Akira Toriyama y se convirti\u00f3 en un \u00e9xito competitivo en el mundo del esport."},
  {t:"m",q:"\u00bfQu\u00e9 actor de doblaje latinoamericano es famoso por ser la voz de Goku en espa\u00f1ol latino?",o:["Mario Casta\u00f1eda","Ricardo Hill","Salvador N\u00e1jar","Luis Alfonso Mendoza"],a:0,exp:"Mario Casta\u00f1eda es la voz ic\u00f3nica de Goku en el doblaje latinoamericano.",extra:"Su interpretaci\u00f3n es considerada la definitiva por millones de fans hispanohablantes y ha continuado el papel desde Dragon Ball Z hasta Dragon Ball Super."},
  {t:"m",q:"\u00bfQu\u00e9 actor de doblaje es famoso por ser la voz de Vegeta en el doblaje latinoamericano?",o:["Ren\u00e9 Garc\u00eda","Mario Casta\u00f1eda","Salvador N\u00e1jar","H\u00e9ctor Moreno"],a:0,exp:"Ren\u00e9 Garc\u00eda es la voz de Vegeta en el doblaje latinoamericano.",extra:"Su interpretaci\u00f3n del orgullo y la arrogancia de Vegeta es tan reconocida que muchos fans no conciben al personaje con otra voz."},
  {t:"m",q:"\u00bfQu\u00e9 diferencia existe entre el doblaje espa\u00f1ol de Espa\u00f1a y el latinoamericano en Dragon Ball?",o:["Son doblajes completamente distintos con actores y traducciones diferentes","Son el mismo doblaje con acento diferente","Espa\u00f1a usa voces japonesas con subt\u00edtulos","Solo el latinoamericano existe"],a:0,exp:"Espa\u00f1a y Latinoam\u00e9rica tienen doblajes completamente distintos para Dragon Ball.",extra:"El doblaje espa\u00f1ol peninsular tiene sus propios actores y traducciones. Algunos t\u00e9rminos difieren: por ejemplo, en Espa\u00f1a se dice 'Bola de Drag\u00f3n' mientras en Latinoam\u00e9rica es 'Esferas del Drag\u00f3n'."},
  {t:"m",q:"\u00bfQu\u00e9 pel\u00edcula de 2022 introduce a Cell Max y las formas Orange Piccolo y Gohan Beast?",o:["Dragon Ball Super: Super Hero","Dragon Ball Super: Broly","Resurrection F","Battle of Gods"],a:0,exp:"Dragon Ball Super: Super Hero (2022) introduce a Orange Piccolo, Gohan Beast y Cell Max.",extra:"Fue la primera pel\u00edcula principal de Dragon Ball animada completamente en CGI 3D, un cambio est\u00e9tico notable respecto a entregas anteriores."},
  {t:"m",q:"\u00bfQu\u00e9 forma alcanza Broly cuando pierde el control durante Dragon Ball Super: Broly?",o:["Broly Super Saiyajin Legendario en furia total","Broly Super Saiyajin 4","Broly Ultra Instinto","Broly Ozaru Dorado Controlado"],a:0,exp:"Broly en la pel\u00edcula de 2018 se transforma en una versi\u00f3n berserker del Super Saiyajin Legendario de poder creciente.",extra:"A diferencia de la versi\u00f3n cl\u00e1sica no can\u00f3nica, el Broly moderno es m\u00e1s tr\u00e1gico: su poder nace del trauma, el aislamiento y el control de Paragus."},
  {t:"m",q:"\u00bfQu\u00e9 planeta eligi\u00f3 Freezer para entrenar durante cuatro meses antes de volver a la Tierra?",o:["Un planeta desconocido","Vampa, el planeta de Broly","El planeta Vegeta reconstruido","Yardrat"],a:0,exp:"Freezer entrena durante cuatro meses en un lugar no especificado para desarrollar el Golden Freezer.",extra:"El hecho de que Freezer nunca hubiera necesitado entrenar antes hace que cuatro meses sean suficientes para alcanzar un nivel que supera todo lo visto anteriormente."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica del Ultra Instinto completo distingue a Goku al dominarlo en el Torneo de Poder?",o:["El cabello plateado y reacciones sin pensar","El cabello dorado y aura azul","El cabello negro y ki oscuro","El cabello rojo y velocidad infinita"],a:0,exp:"El Ultra Instinto Completo se caracteriza por cabello plateado y la capacidad del cuerpo de atacar y defender sin que la mente interfiera.",extra:"Es una t\u00e9cnica que incluso los dioses consideran dif\u00edcil de dominar. Goku logra usarla brevemente contra Jiren, siendo el primer mortal en alcanzarla en combate real."},
  {t:"m",q:"\u00bfQui\u00e9n es el padre biol\u00f3gico de Broly en la versi\u00f3n can\u00f3nica de Dragon Ball Super: Broly (2018)?",o:["Paragus","Freezer","El Rey Vegeta","Raditz"],a:0,exp:"Paragus es el padre de Broly en la pel\u00edcula can\u00f3nica de 2018. Lo rescat\u00f3 del planeta de destierro y lo us\u00f3 para vengarse del Rey Vegeta y de Freezer.",extra:"En esta versi\u00f3n, Paragus es un padre que genuinamente quiere proteger a Broly aunque lo manipula emocionalmente. Su muerte a manos de Freezer desencadena la transformaci\u00f3n descontrolada de Broly."},
  {t:"m",q:"\u00bfQu\u00e9 nueva transformaci\u00f3n de Piccolo se introduce en Dragon Ball Super: Super Hero (2022)?",o:["Orange Piccolo","Purple Piccolo","Black Piccolo","Gold Piccolo"],a:0,exp:"Orange Piccolo es la nueva forma potenciada de Piccolo en Super Hero, obtenida tras absorber el huevo del Gran Drag\u00f3n del Drag\u00f3n Shenr\u00f3n.",extra:"Es la primera transformaci\u00f3n de Piccolo desde el inicio de Z, siendo considerada la m\u00e1s poderosa del personaje. Visualmente se distingue por su color naranja y su mayor tama\u00f1o corporal."}
];

export default dragonballQuestions;
